// Sembly Custom Automation → normalizace payloadu (tvar se může lišit — po prvním běhu uprav pick() podle Execution data)
function pick(obj, ...keys) {
  for (const k of keys) {
    const v = obj && obj[k];
    if (v !== undefined && v !== null && v !== '') return v;
  }
  return undefined;
}

const items = [];
for (const item of $input.all()) {
  let raw = item.json.body !== undefined ? item.json.body : item.json;
  if (typeof raw === 'string') {
    try { raw = JSON.parse(raw); } catch (e) { raw = { _raw_text: raw }; }
  }
  const p = raw && typeof raw === 'object' && !Array.isArray(raw) ? raw : {};
  const nested = p.meeting || p.meeting_data || p.data || {};
  const m = { ...p, ...(typeof nested === 'object' && nested ? nested : {}) };

  const title = pick(m, 'title', 'meeting_title', 'name', 'subject', 'meetingName') || 'Sembly meeting';
  const transcript = String(pick(m, 'meeting_transcription', 'transcript', 'transcription', 'text', 'content', 'full_transcript', 'transcript_text') || '');
  const summary = String(pick(m, 'summary', 'notes', 'description', 'ai_summary', 'meeting_summary') || '');
  let actions = pick(m, 'action_items', 'tasks', 'actions', 'actionItems') || [];
  if (!Array.isArray(actions)) actions = [];
  let attendees = pick(m, 'attendees', 'participants', 'users', 'speakers') || [];
  if (!Array.isArray(attendees)) attendees = [];
  const startRaw = pick(m, 'start_time', 'startTime', 'date', 'created_at', 'meeting_date', 'scheduled_at') || Date.now();
  const date = new Date(startRaw);
  const url = pick(m, 'url', 'permalink', 'link', 'meeting_url', 'web_url') || '—';
  const dur = pick(m, 'duration_minutes', 'duration', 'durationMinutes');

  const ts = `${date.getFullYear()}-${String(date.getMonth()+1).padStart(2,'0')}-${String(date.getDate()).padStart(2,'0')}-${String(date.getHours()).padStart(2,'0')}${String(date.getMinutes()).padStart(2,'0')}`;
  const slug = String(title).toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'').substring(0, 50);
  const filename = `${ts}-${slug || 'meeting'}.md`;

  const attLine = attendees.length
    ? attendees.map(a => (typeof a === 'string' ? a : (a.name || a.email || JSON.stringify(a)))).join(', ')
    : '—';

  const md = [
    `# ${title} — ${date.toLocaleDateString('cs-CZ')} ${date.toLocaleTimeString('cs-CZ', { hour: '2-digit', minute: '2-digit' })}`,
    '',
    `**Účastníci**: ${attLine}`,
    `**Trvání**: ${dur != null && dur !== '' ? `${dur} min` : '?'}`,
    `**Sembly**: ${url}`,
    '',
    '## Shrnutí',
    '',
    summary || '_(prázdné)_',
    '',
    '## Akční body',
    '',
    actions.length
      ? actions.map(a => {
          const t = typeof a === 'string' ? a : (a.text || a.description || a.title || a.name || JSON.stringify(a));
          return `- [ ] ${t}`;
        }).join('\n')
      : '_(žádné)_',
    '',
    '## Plný transkript',
    '',
    transcript || '_(transkript v payloadu nenalezen — v Execution zkontroluj strukturu a uprav mapování v tomto Code uzlu)_',
    ''
  ].join('\n');

  items.push({ json: { filename, content: md } });
}
return items;
